import React, { useEffect, useRef, useState } from 'react';
import { createGame, gameInstance } from './game/phaserGame';
import { GameScene } from './game/scenes/GameScene';
import { Difficulty, GameEvent } from './types';
import { RotateCcw, Flag, Play, HelpCircle, Trophy, Undo, SkipForward, AlertTriangle, Clock, Gauge, X, Check } from 'lucide-react';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<'START' | 'INSTRUCTIONS' | 'PLAYING' | 'VICTORY' | 'FINISHED'>('START');
  const [difficulty, setDifficulty] = useState<Difficulty>(Difficulty.EASY);

  // Session Settings
  const [sessionMinutes, setSessionMinutes] = useState<number>(5);
  const [timeLeft, setTimeLeft] = useState(0);

  // UI State
  const [showRules, setShowRules] = useState(true);
  const [showReportPopup, setShowReportPopup] = useState(false);
  const [showDiffSelector, setShowDiffSelector] = useState(false);
  const [canUndo, setCanUndo] = useState(false);

  // Session Stats
  const [stats, setStats] = useState({
    [Difficulty.EASY]: 0,
    [Difficulty.MEDIUM]: 0,
    [Difficulty.HARD]: 0,
  });

  const timerIntervalRef = useRef<number | null>(null);

  // Ref to hold latest state for the Phaser event callback (avoids stale closures)
  const stateRef = useRef({ difficulty, timeLeft, gameState });

  // Sync state to ref
  useEffect(() => {
    stateRef.current = { difficulty, timeLeft, gameState };
  }, [difficulty, timeLeft, gameState]);

  // Initialize Game
  useEffect(() => {
    const game = createGame('game-container');

    // Bridge Events
    game.events.on('ready', () => {
       const runningScene = game.scene.keys['GameScene'] as GameScene;
       runningScene.onEvent = handleGameEvent;
    });

    return () => {
      game.destroy(true);
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    };
  }, []);

  // Timer Logic: Pause if any modal is open or game is not playing
  useEffect(() => {
    // Timer only runs when explicitly PLAYING and no popups are open
    const isPaused = showRules || showReportPopup || showDiffSelector || gameState !== 'PLAYING';

    if (!isPaused && timeLeft > 0) {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);

      timerIntervalRef.current = window.setInterval(() => {
        setTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    } else {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }

    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    };
  }, [gameState, showRules, showReportPopup, showDiffSelector]); 

  // Check for Session End
  useEffect(() => {
    if (timeLeft === 0 && gameState === 'PLAYING') {
      setGameState('FINISHED');
    }
  }, [timeLeft, gameState]);

  const handleGameEvent = (event: GameEvent) => {
    if (event.type === 'PUZZLE_SOLVED') {
      const { difficulty: currentDifficulty } = stateRef.current;

      setGameState('VICTORY');
      setStats(prev => ({
        ...prev,
        [currentDifficulty]: prev[currentDifficulty] + 1
      }));
    } else if (event.type === 'HISTORY_UPDATE') {
      setCanUndo(event.payload.canUndo);
    }
  };

  const handleStartSession = () => {
    setStats({ [Difficulty.EASY]: 0, [Difficulty.MEDIUM]: 0, [Difficulty.HARD]: 0 });
    setTimeLeft(sessionMinutes * 60);
    // Transition to instructions first, do not start game or timer yet
    setGameState('INSTRUCTIONS');
    setShowRules(false);
  };

  const handleBeginPlay = () => {
    setGameState('PLAYING');
    // Start the first puzzle only after instructions are acknowledged
    launchPuzzle(difficulty);
  }

  const launchPuzzle = (diff: Difficulty) => {
    const scene = gameInstance?.scene.getScene('GameScene') as GameScene;
    if (scene) {
      scene.events.emit('START_GAME', diff);
    }
  };

  const handleNextPuzzle = () => {
    setGameState('PLAYING');
    launchPuzzle(difficulty);
  };

  const handleRestart = () => {
    if (gameState !== 'PLAYING') return;
    const scene = gameInstance?.scene.getScene('GameScene') as GameScene;
    if (scene) {
      scene.events.emit('RESET_PUZZLE');
    }
  };

  const handleSkip = () => {
    if (gameState !== 'PLAYING') return;
    launchPuzzle(difficulty);
  };

  const handleUndo = () => {
    if (gameState !== 'PLAYING') return;
    const scene = gameInstance?.scene.getScene('GameScene') as GameScene;
    if (scene) {
      scene.events.emit('UNDO');
    }
  };

  const handleChangeDifficulty = (newDiff: Difficulty) => {
    setDifficulty(newDiff);
    setShowDiffSelector(false);
    launchPuzzle(newDiff);
  };

  const handleReportClick = () => {
    if (gameState === 'PLAYING') {
      setShowReportPopup(true);
    }
  };

  const confirmReport = () => {
    const scene = gameInstance?.scene.getScene('GameScene') as GameScene;
    if (scene) {
      scene.events.emit('REPORT_UNSOLVABLE');
    }
    handleSkip();
    setShowReportPopup(false);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const getDiffButtonClass = (d: Difficulty) => {
    const isSelected = difficulty === d;
    const base = "py-2 rounded capitalize font-bold transition border-2";

    if (!isSelected) return `${base} bg-slate-700 border-transparent text-slate-400 hover:bg-slate-600`;

    switch (d) {
        case Difficulty.EASY: return `${base} bg-green-600 border-green-400 text-white`;
        case Difficulty.MEDIUM: return `${base} bg-yellow-600 border-yellow-400 text-white`;
        case Difficulty.HARD: return `${base} bg-red-600 border-red-400 text-white`;
        default: return base;
    }
  };

  const getStartButtonClass = () => {
    const base = "w-full py-4 mt-4 rounded font-bold text-lg shadow-lg border-b-4 active:border-b-0 active:translate-y-1 transition text-white";
    switch (difficulty) {
      case Difficulty.EASY: return `${base} bg-green-600 hover:bg-green-500 border-green-800`;
      case Difficulty.MEDIUM: return `${base} bg-yellow-600 hover:bg-yellow-500 border-yellow-800`;
      case Difficulty.HARD: return `${base} bg-red-600 hover:bg-red-500 border-red-800`;
      default: return `${base} bg-blue-600 hover:bg-blue-500 border-blue-800`;
    }
  };

  const totalSolved = stats[Difficulty.EASY] + stats[Difficulty.MEDIUM] + stats[Difficulty.HARD];

  return (
    <div className="relative w-full h-screen bg-slate-900 flex justify-center items-center overflow-hidden p-2">
      {/* Game Container - Scalable 4:3 Box */}
      <div 
        id="game-container" 
        className="relative w-full h-full max-w-[100vw] max-h-full aspect-[4/3] rounded-lg shadow-2xl border-4 border-slate-700 bg-slate-800"
      >
        {/* HUD Overlay - Positioned Inside Container */}
        <div className="absolute inset-0 p-4 pointer-events-none z-10 flex flex-col justify-between">

          {/* TOP BAR */}
          <div className="flex justify-between items-start w-full">
            {/* Top Left: Stats */}
            <div className="bg-slate-800/95 text-white p-3 rounded shadow-lg pointer-events-auto backdrop-blur-sm border border-slate-700 min-w-[140px]">
              <h3 className="font-bold text-yellow-400 mb-2 flex items-center gap-2 border-b border-slate-600 pb-1">
                <Trophy size={16} /> Solved: {totalSolved}
              </h3>
              <div className="text-sm font-mono space-y-1">
                <div className="flex justify-between text-green-400"><span>Easy:</span> <span>{stats[Difficulty.EASY]}</span></div>
                <div className="flex justify-between text-yellow-400"><span>Medium:</span> <span>{stats[Difficulty.MEDIUM]}</span></div>
                <div className="flex justify-between text-red-400"><span>Hard:</span> <span>{stats[Difficulty.HARD]}</span></div>
              </div>
            </div>

            {/* Top Center: Timer */}
            <div className={`bg-slate-800/90 text-white px-6 py-2 rounded-full shadow-lg font-mono text-xl font-bold border-2 backdrop-blur-sm transition-colors ${timeLeft < 30 ? 'border-red-500 text-red-400 animate-pulse' : 'border-slate-600'}`}>
              {formatTime(timeLeft)}
            </div>

            {/* Top Right: Controls */}
            <div className="bg-slate-800/90 p-2 rounded shadow-lg pointer-events-auto flex gap-2 backdrop-blur-sm items-start border border-slate-700">
              <button 
                onClick={() => setShowRules(true)}
                className="bg-blue-600 text-white rounded hover:bg-blue-500 transition w-[44px] flex items-center justify-center h-[96px]" 
                title="Rules"
              >
                <HelpCircle size={24} />
              </button>

              <div className="flex flex-col gap-2">
                <div className="flex gap-2">
                    <button 
                      onClick={handleUndo}
                      disabled={!canUndo || gameState !== 'PLAYING'}
                      className="bg-slate-600 text-white rounded hover:bg-slate-500 transition disabled:opacity-50 disabled:cursor-not-allowed h-[44px] w-[44px] flex items-center justify-center" 
                      title="Undo">
                      <Undo size={20} />
                    </button>
                    <button 
                      onClick={() => setShowDiffSelector(true)}
                      disabled={gameState !== 'PLAYING'}
                      className="bg-purple-600 text-white rounded hover:bg-purple-500 transition disabled:opacity-50 disabled:cursor-not-allowed h-[44px] w-[44px] flex items-center justify-center" 
                      title="Change Difficulty">
                      <Gauge size={20} />
                    </button>
                </div>
                <div className="flex gap-2">
                    <button 
                        onClick={handleRestart}
                        disabled={gameState !== 'PLAYING'}
                        className="bg-orange-600 text-white rounded hover:bg-orange-500 transition disabled:opacity-50 disabled:cursor-not-allowed h-[44px] w-[44px] flex items-center justify-center" 
                        title="Reset Connections">
                        <RotateCcw size={20} />
                      </button>
                    <button 
                      onClick={handleSkip}
                      disabled={gameState !== 'PLAYING'}
                      className="bg-indigo-600 hover:bg-indigo-500 text-white rounded transition disabled:opacity-50 disabled:cursor-not-allowed h-[44px] w-[44px] flex items-center justify-center"
                      title="Skip Puzzle"
                    >
                      <SkipForward size={20} />
                    </button>
                </div>
              </div>
            </div>
          </div>

          {/* Bottom Right: Report */}
          <div className="flex justify-end w-full pointer-events-auto">
             <button 
               onClick={handleReportClick}
               disabled={gameState !== 'PLAYING'}
               className="bg-red-900/80 text-red-200 p-3 rounded-full hover:bg-red-700 transition flex items-center gap-2 border border-red-700 disabled:opacity-0"
               title="Report Unsolvable"
             >
               <Flag size={24} />
             </button>
          </div>
        </div>
      </div>

      {/* --- MODALS --- */}

      {/* Change Difficulty Modal */}
      {showDiffSelector && (
         <div className="absolute inset-0 bg-black/50 flex items-center justify-center z-[60] backdrop-blur-sm">
           <div className="bg-slate-800 text-white p-6 rounded-lg shadow-2xl border border-purple-500">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-purple-400">Change Difficulty</h3>
                <button onClick={() => setShowDiffSelector(false)} className="hover:text-red-400"><X size={20}/></button>
              </div>
              <div className="grid grid-cols-1 gap-3 w-64">
                {[Difficulty.EASY, Difficulty.MEDIUM, Difficulty.HARD].map(d => (
                  <button
                    key={d}
                    onClick={() => handleChangeDifficulty(d)}
                    className={getDiffButtonClass(d)}
                  >
                    {d}
                  </button>
                ))}
              </div>
              <p className="text-xs text-slate-400 mt-4 text-center">Note: Current puzzle will be skipped.</p>
           </div>
         </div>
      )}

      {/* Report Popup */}
      {showReportPopup && (
        <div className="absolute inset-0 bg-black/80 flex items-center justify-center z-[60] backdrop-blur-sm animate-fade-in">
          <div className="bg-slate-800 text-white p-6 rounded-lg max-w-sm w-full shadow-2xl border-2 border-red-500 text-center">
            <AlertTriangle className="mx-auto text-red-500 mb-4" size={48} />
            <h2 className="text-xl font-bold mb-2">Report Puzzle</h2>
            <p className="text-slate-300 mb-6">
              This puzzle will be inspected for errors. You will be moved to a new puzzle.
            </p>
            <div className="flex gap-4 justify-center">
              <button 
                onClick={() => setShowReportPopup(false)}
                className="px-4 py-2 bg-slate-600 hover:bg-slate-500 rounded font-bold"
              >
                Cancel
              </button>
              <button 
                onClick={confirmReport}
                className="px-4 py-2 bg-red-600 hover:bg-red-500 rounded font-bold"
              >
                Confirm
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Start / Instructions / Rules Modal */}
      {(gameState === 'START' || gameState === 'INSTRUCTIONS' || showRules) && (
        <div className="absolute inset-0 bg-black/80 flex items-center justify-center z-50 backdrop-blur-md">
          <div className="bg-slate-800 text-white p-8 rounded-lg max-w-lg w-full shadow-2xl border border-slate-600">
            <h1 className="text-4xl font-bold text-yellow-400 mb-2 text-center tracking-tight">POWER GRID</h1>
            <h2 className="text-xl text-slate-400 mb-6 text-center font-mono">HASHI PUZZLE</h2>

            {gameState === 'START' ? (
              <div className="space-y-6">

                {/* Time Selection */}
                <div>
                   <label className="block text-slate-300 text-sm font-bold mb-2 flex items-center gap-2">
                     <Clock size={16} /> Session Duration
                   </label>
                   <div className="grid grid-cols-4 gap-2">
                     {[3, 5, 10, 20].map(m => (
                       <button
                         key={m}
                         onClick={() => setSessionMinutes(m)}
                         className={`py-2 rounded font-mono font-bold transition border-2 ${sessionMinutes === m ? 'bg-yellow-500 border-yellow-600 text-slate-900' : 'bg-slate-700 border-transparent text-slate-400 hover:bg-slate-600'}`}
                       >
                         {m}m
                       </button>
                     ))}
                   </div>
                </div>

                {/* Difficulty Selection */}
                <div>
                   <label className="block text-slate-300 text-sm font-bold mb-2 flex items-center gap-2">
                     <Gauge size={16} /> Starting Difficulty
                   </label>
                   <div className="grid grid-cols-3 gap-2">
                     {[Difficulty.EASY, Difficulty.MEDIUM, Difficulty.HARD].map(d => (
                       <button
                         key={d}
                         onClick={() => setDifficulty(d)}
                         className={getDiffButtonClass(d)}
                       >
                         {d}
                       </button>
                     ))}
                   </div>
                </div>

                <button 
                   onClick={handleStartSession}
                   className={getStartButtonClass()}
                >
                   NEXT
                </button>

                <div className="text-xs text-center text-slate-500 mt-4">
                   Instructions on next screen
                </div>
              </div>
            ) : (
              // Rules / Instructions View
              // Shows either when "showRules" is true during game OR when in "INSTRUCTIONS" state before game
              <div className="space-y-4">
                  <div className="text-center mb-4">
                    <h3 className="text-lg font-bold text-white uppercase tracking-widest border-b border-slate-600 pb-2 inline-block">How to Play</h3>
                  </div>
                  <div className="bg-slate-700/50 p-6 rounded text-sm leading-relaxed text-slate-200 shadow-inner">
                    <ul className="list-disc pl-5 space-y-3">
                        <li>Connect houses with power cables.</li>
                        <li>The number on a house represents the <strong>exact number</strong> of cables connected to it.</li>
                        <li>You can have up to <strong>2 cables</strong> between two houses.</li>
                        <li>Cables can only run horizontally or vertically.</li>
                        <li><strong>Lines cannot cross</strong> each other.</li>
                        <li>All houses must be connected into a single power network.</li>
                    </ul>
                  </div>

                  <button 
                    onClick={gameState === 'INSTRUCTIONS' ? handleBeginPlay : () => setShowRules(false)}
                    className="w-full py-4 mt-2 bg-green-600 hover:bg-green-500 text-white rounded font-bold text-lg flex items-center justify-center gap-2 transition"
                  >
                    {gameState === 'INSTRUCTIONS' ? (
                       <>Got it <Check size={20} /></>
                    ) : (
                       "Resume Game"
                    )}
                  </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Victory Modal (Intermediate) */}
      {gameState === 'VICTORY' && (
        <div className="absolute inset-0 bg-yellow-500/10 flex items-center justify-center z-50 backdrop-blur-sm">
          <div className="bg-slate-800 text-white p-8 rounded-lg text-center shadow-2xl border-2 border-yellow-400 animate-bounce-in min-w-[300px]">
             <h2 className="text-3xl font-bold text-yellow-400 mb-2">Grid Online!</h2>
             <div className="text-green-400 font-mono mb-6">System Stable</div>

             <button 
               onClick={handleNextPuzzle}
               className="w-full bg-green-600 hover:bg-green-500 text-white px-8 py-4 rounded-lg font-bold text-lg flex items-center justify-center gap-2 transition shadow-lg border-b-4 border-green-800 active:border-b-0 active:translate-y-1"
             >
               Next Puzzle <Play size={20} fill="currentColor" />
             </button>
          </div>
        </div>
      )}

      {/* Session Finished Modal */}
      {gameState === 'FINISHED' && (
        <div className="absolute inset-0 bg-slate-900/90 flex items-center justify-center z-50 backdrop-blur-md">
          <div className="bg-slate-800 text-white p-8 rounded-lg text-center shadow-2xl border-4 border-slate-600 max-w-md w-full animate-fade-in">
             <Clock className="mx-auto text-slate-400 mb-4" size={64} />
             <h2 className="text-4xl font-bold text-white mb-2">SESSION COMPLETE</h2>
             <p className="text-slate-400 mb-8">Time Limit Reached</p>

             <div className="bg-slate-900 rounded-lg p-6 mb-8 border border-slate-700">
                <div className="text-5xl font-bold text-yellow-400 mb-2">{totalSolved}</div>
                <div className="text-sm text-slate-500 uppercase tracking-widest mb-6">Total Puzzles Solved</div>

                <div className="grid grid-cols-3 gap-2 text-sm border-t border-slate-800 pt-4">
                   <div>
                      <div className="font-bold text-green-400">{stats[Difficulty.EASY]}</div>
                      <div className="text-slate-600">Easy</div>
                   </div>
                   <div>
                      <div className="font-bold text-yellow-400">{stats[Difficulty.MEDIUM]}</div>
                      <div className="text-slate-600">Medium</div>
                   </div>
                   <div>
                      <div className="font-bold text-red-400">{stats[Difficulty.HARD]}</div>
                      <div className="text-slate-600">Hard</div>
                   </div>
                </div>
             </div>

             <button 
               onClick={() => setGameState('START')}
               className="w-full bg-blue-600 hover:bg-blue-500 text-white px-6 py-4 rounded-lg font-bold text-lg transition shadow-lg"
             >
               New Session
             </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import * as Phaser from 'phaser';
import { NodeData } from '../../types';

export class House extends Phaser.GameObjects.Container {
  public dataModel: NodeData;
  private base: Phaser.GameObjects.Graphics;
  private roof: Phaser.GameObjects.Graphics;
  private text: Phaser.GameObjects.Text;
  private highlight: Phaser.GameObjects.Graphics;
  private isPowered: boolean = false;
  private isSelected: boolean = false;

  constructor(scene: Phaser.Scene, x: number, y: number, data: NodeData, scale: number) {
    super(scene, x, y);
    this.dataModel = data;
    this.setScale(scale);

    // Create visual components
    this.base = scene.make.graphics({ x: 0, y: 0 }, false);
    this.roof = scene.make.graphics({ x: 0, y: 0 }, false);
    this.highlight = scene.make.graphics({ x: 0, y: 0 }, false);

    // Number text
    this.text = scene.add.text(0, 0, data.requiredConnections.toString(), {
      fontSize: '24px',
      color: '#ffffff',
      fontFamily: 'Rubik, sans-serif',
      fontStyle: 'bold'
    });
    this.text.setOrigin(0.5, 0.5);

    this.add([this.highlight, this.base, this.roof, this.text]);

    // Bounds for interaction
    this.setSize(60, 60);
    this.setInteractive({ cursor: 'pointer' });

    this.redraw();
  }

  public setSelection(selected: boolean) {
    this.isSelected = selected;
    this.redraw();
  }

  public setPowered(powered: boolean) {
    if (this.isPowered !== powered) {
      this.isPowered = powered;
      this.redraw();

      // Animation pulse when powered
      if (powered) {
        this.scene.tweens.add({
          targets: this,
          scale: this.scaleX * 1.1,
          duration: 100,
          yoyo: true,
          ease: 'Sine.easeInOut'
        });
      }
    }
  }

  public updateConnectionCount(count: number) {
    this.dataModel.currentConnections = count;
    // Check if full (but not necessarily powered network-wise)
    // We visually indicate "satisfied valence" vs "part of complete network" differently?
    // Spec says: "Powered: Yellow/gold when puzzle solved". 
    // But usually in Hashi, node dims if satisfied.
    // We will stick to the spec: "Powered" happens when WHOLE puzzle solved.
    // However, user needs feedback on count.

    const satisfied = this.dataModel.currentConnections === this.dataModel.requiredConnections;
    const overflow = this.dataModel.currentConnections > this.dataModel.requiredConnections;

    if (overflow) {
      this.text.setColor('#ff4444'); // Red if too many
    } else if (satisfied) {
      this.text.setColor('#aaffaa'); // Light green if satisfied
    } else {
      this.text.setColor('#ffffff');
    }
  }

  private redraw() {
    this.base.clear();
    this.roof.clear();
    this.highlight.clear();

    const w = 50;
    const h = 40;
    const roofH = 20;

    // Selection Highlight
    if (this.isSelected) {
      this.highlight.lineStyle(4, 0xffff00, 0.8);
      this.highlight.strokeCircle(0, 5, 45);
    }

    // Base Color
    const baseColor = this.isPowered ? 0xffcc00 : 0x8d6e63; // Gold or Brown
    const roofColor = this.isPowered ? 0xffeb3b : 0x5d4037; // Lighter Gold or Dark Brown

    // Draw House Base
    this.base.fillStyle(baseColor);
    this.base.fillRect(-w/2, -h/2 + 10, w, h);

    // Draw Roof
    this.roof.fillStyle(roofColor);
    this.roof.beginPath();
    this.roof.moveTo(-w/2 - 5, -h/2 + 10);
    this.roof.lineTo(0, -h/2 - roofH + 10);
    this.roof.lineTo(w/2 + 5, -h/2 + 10);
    this.roof.closePath();
    this.roof.fill();

    // Windows/Door detail (simple lines)
    this.base.fillStyle(0x3e2723);
    this.base.fillRect(-10, 10, 20, 20); // Door
  }
}

import * as Phaser from 'phaser';
import { House } from '../objects/House';
import { CableManager } from '../systems/CableManager';
import { PuzzleGenerator } from '../systems/PuzzleGenerator';
import { Difficulty, DIFFICULTY_SETTINGS, NodeData } from '../../types';

interface MoveAction {
  nodeAId: string;
  nodeBId: string;
  previousCount: number;
}

export class GameScene extends Phaser.Scene {
  private houses: House[] = [];
  private cableManager!: CableManager;
  private selectedHouse: House | null = null;
  private isSolved: boolean = false;
  private currentDifficulty: Difficulty = Difficulty.EASY;

  // Undo History
  private history: MoveAction[] = [];

  // Grid config
  private gridOffsetX = 0;
  private gridOffsetY = 0;
  private cellSize = 80;

  // React Bridge
  public onEvent?: (event: any) => void;

  constructor() {
    super('GameScene');
  }

  create() {
    this.createBackground();
    this.cableManager = new CableManager(this);

    // Listen for events from React
    this.events.on('START_GAME', (difficulty: Difficulty) => {
      this.startGame(difficulty);
    });

    this.events.on('RESET_PUZZLE', () => {
      this.resetCurrentPuzzle();
    });

    this.events.on('REPORT_UNSOLVABLE', () => {
       // Logic to log and skip
       console.log("Player reported unsolvable.");
       // Usually followed by a start game from React, but we ensures cleanup here if needed
    });

    this.events.on('UNDO', () => {
      this.undo();
    });
  }

  private createBackground() {
    const bg = this.add.graphics();
    const w = this.scale.width;
    const h = this.scale.height;

    // Base Color (Bright Grass Green) - Matches the background of the image provided
    bg.fillStyle(0x8bc34a); 
    bg.fillRect(0, 0, w, h);

    // Grass Tufts Pattern
    // Use a slightly darker green for the tufts to create the texture effect
    bg.fillStyle(0x689f38); 

    // Procedurally scatter grass tufts across the screen
    // This mimics the texture without needing an external asset
    const density = 2500; // Number of tufts

    for (let i = 0; i < density; i++) {
        const x = Math.random() * w;
        const y = Math.random() * h;

        // Draw a simple 3-blade tuft
        bg.beginPath();

        // Center blade
        bg.moveTo(x, y);
        bg.lineTo(x + 2, y - 8);
        bg.lineTo(x + 4, y);

        // Left blade
        bg.moveTo(x, y);
        bg.lineTo(x - 3, y - 6);
        bg.lineTo(x - 1, y);

        // Right blade
        bg.moveTo(x + 4, y);
        bg.lineTo(x + 7, y - 6);
        bg.lineTo(x + 5, y);

        bg.fillPath();
    }

    // Apply blur to background to reduce visual noise and make gameplay elements pop
    // Using PostFX (Requires WebGL)
    if (this.game.renderer.type === Phaser.WEBGL) {
       // Strength of 4 provides a significant blur (~45% feeling of softness)
       bg.postFX.addBlur(1, 4, 4, 1);
    }
  }

  public startGame(difficulty: Difficulty) {
    this.currentDifficulty = difficulty;
    this.isSolved = false;
    this.selectedHouse = null;
    this.history = [];
    this.notifyHistoryChange();

    // Cleanup
    this.houses.forEach(h => h.destroy());
    this.houses = [];
    this.cableManager.reset();

    // Generate
    const puzzle = PuzzleGenerator.generate(difficulty);

    // Calculate Layout
    const settings = DIFFICULTY_SETTINGS[difficulty];
    const gridSize = settings.gridSize;
    // Fit grid to screen
    const availWidth = this.scale.width * 0.9;
    const availHeight = this.scale.height * 0.8; // leave room for HUD
    this.cellSize = Math.min(availWidth / gridSize, availHeight / gridSize);

    this.gridOffsetX = (this.scale.width - (gridSize - 1) * this.cellSize) / 2;
    this.gridOffsetY = (this.scale.height - (gridSize - 1) * this.cellSize) / 2 + 30; // Push down slightly

    // Create Houses
    puzzle.nodes.forEach(nodeData => {
      const x = this.gridOffsetX + nodeData.x * this.cellSize;
      const y = this.gridOffsetY + nodeData.y * this.cellSize;

      const house = new House(this, x, y, nodeData, settings.scale);
      house.name = nodeData.id; // For lookup

      house.on('pointerdown', () => this.handleHouseClick(house));

      this.add.existing(house);
      this.houses.push(house);
    });
  }

  private resetCurrentPuzzle() {
    if (this.isSolved) return; // Optional: Allow reset even if solved? Spec says button disabled if solved.

    // 1. Reset Cables
    this.cableManager.reset();

    // 2. Reset Houses visual state
    this.houses.forEach(h => {
      h.updateConnectionCount(0);
      h.setPowered(false);
      h.setSelection(false);
    });

    // 3. Reset State
    this.selectedHouse = null;
    this.history = [];
    this.notifyHistoryChange();
    this.isSolved = false;
  }

  private handleHouseClick(house: House) {
    if (this.isSolved) return;

    if (!this.selectedHouse) {
      // Select
      this.selectedHouse = house;
      house.setSelection(true);
    } else if (this.selectedHouse === house) {
      // Deselect
      this.selectedHouse.setSelection(false);
      this.selectedHouse = null;
    } else {
      // Attempt Connection
      if (this.cableManager.canConnect(this.selectedHouse, house, this.houses)) {
        // Record History before change
        const prevCount = this.cableManager.hasConnection(this.selectedHouse.dataModel.id, house.dataModel.id);
        this.history.push({
          nodeAId: this.selectedHouse.dataModel.id,
          nodeBId: house.dataModel.id,
          previousCount: prevCount
        });
        this.notifyHistoryChange();

        this.cableManager.toggleConnection(this.selectedHouse, house);
        this.checkWinCondition();
      }

      // Always Deselect after action
      this.selectedHouse.setSelection(false);
      this.selectedHouse = null;
    }
  }

  private undo() {
    if (this.history.length === 0 || this.isSolved) return;

    const lastMove = this.history.pop();
    this.notifyHistoryChange();

    if (lastMove) {
      const houseA = this.houses.find(h => h.dataModel.id === lastMove.nodeAId);
      const houseB = this.houses.find(h => h.dataModel.id === lastMove.nodeBId);

      if (houseA && houseB) {
        this.cableManager.setConnection(houseA, houseB, lastMove.previousCount);
        this.checkWinCondition();
      }
    }
  }

  private notifyHistoryChange() {
    if (this.onEvent) {
      this.onEvent({ type: 'HISTORY_UPDATE', payload: { canUndo: this.history.length > 0 } });
    }
  }

  private checkWinCondition() {
    // 1. Update Connection Counts for all nodes
    const edges = this.cableManager.getAllEdges();

    // Reset counts
    this.houses.forEach(h => h.updateConnectionCount(0));

    // Sum up
    edges.forEach(e => {
      const hA = this.houses.find(h => h.dataModel.id === e.nodeA);
      const hB = this.houses.find(h => h.dataModel.id === e.nodeB);
      if (hA) hA.updateConnectionCount(hA.dataModel.currentConnections + e.count);
      if (hB) hB.updateConnectionCount(hB.dataModel.currentConnections + e.count);
    });

    // 2. Validate Counts
    const allCountsCorrect = this.houses.every(h => h.dataModel.currentConnections === h.dataModel.requiredConnections);

    if (!allCountsCorrect) return;

    // 3. Validate Connectivity (BFS)
    if (this.houses.length === 0) return;

    const startId = this.houses[0].dataModel.id;
    const visited = new Set<string>();
    const queue = [startId];
    visited.add(startId);

    // Build Adjacency List for BFS
    const adj = new Map<string, string[]>();
    edges.forEach(e => {
      if (!adj.has(e.nodeA)) adj.set(e.nodeA, []);
      if (!adj.has(e.nodeB)) adj.set(e.nodeB, []);
      adj.get(e.nodeA)?.push(e.nodeB);
      adj.get(e.nodeB)?.push(e.nodeA);
    });

    while (queue.length > 0) {
      const curr = queue.shift()!;
      const neighbors = adj.get(curr) || [];
      for (const n of neighbors) {
        if (!visited.has(n)) {
          visited.add(n);
          queue.push(n);
        }
      }
    }

    const allConnected = visited.size === this.houses.length;

    if (allConnected) {
      this.victory();
    }
  }

  private victory() {
    this.isSolved = true;
    this.houses.forEach(h => h.setPowered(true));
    this.cableManager.setSolvedState(true);

    // Play sound effect
    this.playVictorySound();

    if (this.onEvent) {
      this.onEvent({ type: 'PUZZLE_SOLVED' });
    }
  }

  private playVictorySound() {
    // Simple Web Audio API synthesis for "Power Up" whirring sound
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;

      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      // Sawtooth wave for a buzzy "electric" feel
      osc.type = 'sawtooth';

      // Pitch ramp up (Powering up)
      osc.frequency.setValueAtTime(110, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(440, ctx.currentTime + 0.4);

      // Volume envelope
      gain.gain.setValueAtTime(0.05, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.1, ctx.currentTime + 0.3);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.2);

      osc.connect(gain);
      gain.connect(ctx.destination);

      osc.start();
      osc.stop(ctx.currentTime + 1.2);

      // Add a second layer (Higher pitch spark)
      const spark = ctx.createOscillator();
      const sparkGain = ctx.createGain();
      spark.type = 'square';
      spark.frequency.setValueAtTime(880, ctx.currentTime);
      spark.frequency.linearRampToValueAtTime(1200, ctx.currentTime + 0.1);

      sparkGain.gain.setValueAtTime(0.03, ctx.currentTime);
      sparkGain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);

      spark.connect(sparkGain);
      sparkGain.connect(ctx.destination);
      spark.start();
      spark.stop(ctx.currentTime + 0.3);

    } catch (e) {
      console.warn("Audio Context not supported or failed", e);
    }
  }
}

import * as Phaser from 'phaser';
import { EdgeData, NodeData } from '../../types';
import { House } from '../objects/House';

export class CableManager {
  private scene: Phaser.Scene;
  private graphics: Phaser.GameObjects.Graphics;
  private edges: Map<string, EdgeData>; // Key: "idA-idB" (sorted)

  constructor(scene: Phaser.Scene) {
    this.scene = scene;
    this.graphics = scene.add.graphics();
    this.edges = new Map();
  }

  public reset() {
    this.edges.clear();
    this.graphics.clear();
  }

  public getEdgeKey(idA: string, idB: string): string {
    return idA < idB ? `${idA}-${idB}` : `${idB}-${idA}`;
  }

  public hasConnection(idA: string, idB: string): number {
    const key = this.getEdgeKey(idA, idB);
    return this.edges.get(key)?.count || 0;
  }

  public toggleConnection(nodeA: House, nodeB: House): number {
    const key = this.getEdgeKey(nodeA.dataModel.id, nodeB.dataModel.id);
    const current = this.edges.get(key);

    let newCount = 0;
    if (!current) {
      newCount = 1;
    } else if (current.count === 1) {
      newCount = 2;
    } else {
      newCount = 0;
    }

    if (newCount === 0) {
      this.edges.delete(key);
    } else {
      this.edges.set(key, { 
        nodeA: nodeA.dataModel.id, 
        nodeB: nodeB.dataModel.id, 
        count: newCount 
      });
    }

    this.draw();
    return newCount;
  }

  public setConnection(nodeA: House, nodeB: House, count: number) {
    const key = this.getEdgeKey(nodeA.dataModel.id, nodeB.dataModel.id);

    if (count === 0) {
      this.edges.delete(key);
    } else {
      this.edges.set(key, { 
        nodeA: nodeA.dataModel.id, 
        nodeB: nodeB.dataModel.id, 
        count: count 
      });
    }

    this.draw();
  }

  public canConnect(nodeA: House, nodeB: House, allNodes: House[]): boolean {
    const dA = nodeA.dataModel;
    const dB = nodeB.dataModel;

    // 1. Orthogonal check
    if (dA.x !== dB.x && dA.y !== dB.y) return false;

    // 2. Node between check
    const isVertical = dA.x === dB.x;
    for (const other of allNodes) {
      if (other === nodeA || other === nodeB) continue;
      const dO = other.dataModel;

      if (isVertical) {
        if (dO.x === dA.x && 
           ((dO.y > dA.y && dO.y < dB.y) || (dO.y > dB.y && dO.y < dA.y))) return false;
      } else {
        if (dO.y === dA.y && 
           ((dO.x > dA.x && dO.x < dB.x) || (dO.x > dB.x && dO.x < dA.x))) return false;
      }
    }

    // 3. Cable crossing check
    // Logic: If we are drawing vertical, check against all horizontal edges in range
    const newMinX = Math.min(dA.x, dB.x);
    const newMaxX = Math.max(dA.x, dB.x);
    const newMinY = Math.min(dA.y, dB.y);
    const newMaxY = Math.max(dA.y, dB.y);

    for (const edge of this.edges.values()) {
      const n1 = allNodes.find(n => n.dataModel.id === edge.nodeA)!;
      const n2 = allNodes.find(n => n.dataModel.id === edge.nodeB)!;

      // Skip if connected to same nodes (updating existing edge is fine)
      if (edge.nodeA === dA.id || edge.nodeA === dB.id || 
          edge.nodeB === dA.id || edge.nodeB === dB.id) continue;

      const eIsVert = n1.dataModel.x === n2.dataModel.x;

      if (isVertical && !eIsVert) {
        // New is Vert, Existing is Horiz -> Possible cross
        const eY = n1.dataModel.y;
        const eMinX = Math.min(n1.dataModel.x, n2.dataModel.x);
        const eMaxX = Math.max(n1.dataModel.x, n2.dataModel.x);

        if (dA.x > eMinX && dA.x < eMaxX && eY > newMinY && eY < newMaxY) return false;
      } else if (!isVertical && eIsVert) {
        // New is Horiz, Existing is Vert -> Possible cross
        const eX = n1.dataModel.x;
        const eMinY = Math.min(n1.dataModel.y, n2.dataModel.y);
        const eMaxY = Math.max(n1.dataModel.y, n2.dataModel.y);

        if (dA.y > eMinY && dA.y < eMaxY && eX > newMinX && eX < newMaxX) return false;
      }
    }

    return true;
  }

  public getAllEdges() {
    return Array.from(this.edges.values());
  }

  public setSolvedState(isSolved: boolean) {
    this.draw(isSolved);
  }

  private draw(isSolved: boolean = false) {
    this.graphics.clear();
    const color = isSolved ? 0xffcc00 : 0x666666;

    this.edges.forEach(edge => {
      const nodeA = this.scene.children.getByName(edge.nodeA) as House;
      const nodeB = this.scene.children.getByName(edge.nodeB) as House;

      if (nodeA && nodeB) {
        if (edge.count === 1) {
          // Changed from 3 to 4
          this.graphics.lineStyle(4, color, 1);
          this.graphics.beginPath();
          this.graphics.moveTo(nodeA.x, nodeA.y);
          this.graphics.lineTo(nodeB.x, nodeB.y);
          this.graphics.strokePath();
        } else {
          // Double line
          const isVert = nodeA.x === nodeB.x;
          const offset = 5;

          // Changed from 2 to 3
          this.graphics.lineStyle(3, color, 1);

          if (isVert) {
            this.graphics.beginPath();
            this.graphics.moveTo(nodeA.x - offset, nodeA.y);
            this.graphics.lineTo(nodeB.x - offset, nodeB.y);
            this.graphics.moveTo(nodeA.x + offset, nodeA.y);
            this.graphics.lineTo(nodeB.x + offset, nodeB.y);
            this.graphics.strokePath();
          } else {
            this.graphics.beginPath();
            this.graphics.moveTo(nodeA.x, nodeA.y - offset);
            this.graphics.lineTo(nodeB.x, nodeB.y - offset);
            this.graphics.moveTo(nodeA.x, nodeA.y + offset);
            this.graphics.lineTo(nodeB.x, nodeB.y + offset);
            this.graphics.strokePath();
          }
        }
      }
    });
  }
}

import Phaser from 'phaser';
import { NodeData } from '../../types';

export class House extends Phaser.GameObjects.Container {
  public dataModel: NodeData;
  private base: Phaser.GameObjects.Graphics;
  private roof: Phaser.GameObjects.Graphics;
  private text: Phaser.GameObjects.Text;
  private highlight: Phaser.GameObjects.Graphics;
  private isPowered: boolean = false;
  private isSelected: boolean = false;

  constructor(scene: Phaser.Scene, x: number, y: number, data: NodeData, scale: number) {
    super(scene, x, y);
    this.dataModel = data;
    this.setScale(scale);

    // Create visual components
    this.base = scene.make.graphics({ x: 0, y: 0 }, false);
    this.roof = scene.make.graphics({ x: 0, y: 0 }, false);
    this.highlight = scene.make.graphics({ x: 0, y: 0 }, false);

    // Number text
    this.text = scene.add.text(0, 0, data.requiredConnections.toString(), {
      fontSize: '24px',
      color: '#ffffff',
      fontFamily: 'Rubik, sans-serif',
      fontStyle: 'bold'
    });
    this.text.setOrigin(0.5, 0.5);

    this.add([this.highlight, this.base, this.roof, this.text]);

    // Bounds for interaction
    this.setSize(60, 60);
    this.setInteractive({ cursor: 'pointer' });

    this.redraw();
  }

  public setSelection(selected: boolean) {
    this.isSelected = selected;
    this.redraw();
  }

  public setPowered(powered: boolean) {
    if (this.isPowered !== powered) {
      this.isPowered = powered;
      this.redraw();

      // Animation pulse when powered
      if (powered) {
        this.scene.tweens.add({
          targets: this,
          scale: this.scaleX * 1.1,
          duration: 100,
          yoyo: true,
          ease: 'Sine.easeInOut'
        });
      }
    }
  }

  public updateConnectionCount(count: number) {
    this.dataModel.currentConnections = count;
    // Check if full (but not necessarily powered network-wise)
    // We visually indicate "satisfied valence" vs "part of complete network" differently?
    // Spec says: "Powered: Yellow/gold when puzzle solved". 
    // But usually in Hashi, node dims if satisfied.
    // We will stick to the spec: "Powered" happens when WHOLE puzzle solved.
    // However, user needs feedback on count.

    const satisfied = this.dataModel.currentConnections === this.dataModel.requiredConnections;
    const overflow = this.dataModel.currentConnections > this.dataModel.requiredConnections;

    if (overflow) {
      this.text.setColor('#ff4444'); // Red if too many
    } else if (satisfied) {
      this.text.setColor('#aaffaa'); // Light green if satisfied
    } else {
      this.text.setColor('#ffffff');
    }
  }

  private redraw() {
    this.base.clear();
    this.roof.clear();
    this.highlight.clear();

    const w = 50;
    const h = 40;
    const roofH = 20;

    // Selection Highlight
    if (this.isSelected) {
      this.highlight.lineStyle(4, 0xffff00, 0.8);
      this.highlight.strokeCircle(0, 5, 45);
    }

    // Base Color
    const baseColor = this.isPowered ? 0xffcc00 : 0x8d6e63; // Gold or Brown
    const roofColor = this.isPowered ? 0xffeb3b : 0x5d4037; // Lighter Gold or Dark Brown

    // Draw House Base
    this.base.fillStyle(baseColor);
    this.base.fillRect(-w/2, -h/2 + 10, w, h);

    // Draw Roof
    this.roof.fillStyle(roofColor);
    this.roof.beginPath();
    this.roof.moveTo(-w/2 - 5, -h/2 + 10);
    this.roof.lineTo(0, -h/2 - roofH + 10);
    this.roof.lineTo(w/2 + 5, -h/2 + 10);
    this.roof.closePath();
    this.roof.fill();

    // Windows/Door detail (simple lines)
    this.base.fillStyle(0x3e2723);
    this.base.fillRect(-10, 10, 20, 20); // Door
  }
}

import Phaser from 'phaser';
import { House } from '../objects/House';
import { CableManager } from '../systems/CableManager';
import { PuzzleGenerator } from '../systems/PuzzleGenerator';
import { Difficulty, DIFFICULTY_SETTINGS, NodeData } from '../../types';

interface MoveAction {
  nodeAId: string;
  nodeBId: string;
  previousCount: number;
}

export class GameScene extends Phaser.Scene {
  private houses: House[] = [];
  private cableManager!: CableManager;
  private selectedHouse: House | null = null;
  private isSolved: boolean = false;
  private currentDifficulty: Difficulty = Difficulty.EASY;

  // Undo History
  private history: MoveAction[] = [];

  // Grid config
  private gridOffsetX = 0;
  private gridOffsetY = 0;
  private cellSize = 80;

  // React Bridge
  public onEvent?: (event: any) => void;

  constructor() {
    super('GameScene');
  }

  create() {
    this.createBackground();
    this.cableManager = new CableManager(this);

    // Listen for events from React
    this.events.on('START_GAME', (difficulty: Difficulty) => {
      this.startGame(difficulty);
    });

    this.events.on('RESET_PUZZLE', () => {
      this.resetCurrentPuzzle();
    });

    this.events.on('REPORT_UNSOLVABLE', () => {
       // Logic to log and skip
       console.log("Player reported unsolvable.");
       // Usually followed by a start game from React, but we ensures cleanup here if needed
    });

    this.events.on('UNDO', () => {
      this.undo();
    });
  }

  private createBackground() {
    const bg = this.add.graphics();
    const w = this.scale.width;
    const h = this.scale.height;

    // Base Color (Bright Grass Green) - Matches the background of the image provided
    bg.fillStyle(0x8bc34a); 
    bg.fillRect(0, 0, w, h);

    // Grass Tufts Pattern
    // Use a slightly darker green for the tufts to create the texture effect
    bg.fillStyle(0x689f38); 

    // Procedurally scatter grass tufts across the screen
    // This mimics the texture without needing an external asset
    const density = 2500; // Number of tufts

    for (let i = 0; i < density; i++) {
        const x = Math.random() * w;
        const y = Math.random() * h;

        // Draw a simple 3-blade tuft
        bg.beginPath();

        // Center blade
        bg.moveTo(x, y);
        bg.lineTo(x + 2, y - 8);
        bg.lineTo(x + 4, y);

        // Left blade
        bg.moveTo(x, y);
        bg.lineTo(x - 3, y - 6);
        bg.lineTo(x - 1, y);

        // Right blade
        bg.moveTo(x + 4, y);
        bg.lineTo(x + 7, y - 6);
        bg.lineTo(x + 5, y);

        bg.fillPath();
    }

    // Apply blur to background to reduce visual noise and make gameplay elements pop
    // Using PostFX (Requires WebGL)
    if (this.game.renderer.type === Phaser.WEBGL) {
       // Strength of 4 provides a significant blur (~45% feeling of softness)
       bg.postFX.addBlur(1, 4, 4, 1);
    }
  }

  public startGame(difficulty: Difficulty) {
    this.currentDifficulty = difficulty;
    this.isSolved = false;
    this.selectedHouse = null;
    this.history = [];
    this.notifyHistoryChange();

    // Cleanup
    this.houses.forEach(h => h.destroy());
    this.houses = [];
    this.cableManager.reset();

    // Generate
    const puzzle = PuzzleGenerator.generate(difficulty);

    // Calculate Layout
    const settings = DIFFICULTY_SETTINGS[difficulty];
    const gridSize = settings.gridSize;
    // Fit grid to screen
    const availWidth = this.scale.width * 0.9;
    const availHeight = this.scale.height * 0.8; // leave room for HUD
    this.cellSize = Math.min(availWidth / gridSize, availHeight / gridSize);

    this.gridOffsetX = (this.scale.width - (gridSize - 1) * this.cellSize) / 2;
    this.gridOffsetY = (this.scale.height - (gridSize - 1) * this.cellSize) / 2 + 30; // Push down slightly

    // Create Houses
    puzzle.nodes.forEach(nodeData => {
      const x = this.gridOffsetX + nodeData.x * this.cellSize;
      const y = this.gridOffsetY + nodeData.y * this.cellSize;

      const house = new House(this, x, y, nodeData, settings.scale);
      house.name = nodeData.id; // For lookup

      house.on('pointerdown', () => this.handleHouseClick(house));

      this.add.existing(house);
      this.houses.push(house);
    });
  }

  private resetCurrentPuzzle() {
    if (this.isSolved) return; // Optional: Allow reset even if solved? Spec says button disabled if solved.

    // 1. Reset Cables
    this.cableManager.reset();

    // 2. Reset Houses visual state
    this.houses.forEach(h => {
      h.updateConnectionCount(0);
      h.setPowered(false);
      h.setSelection(false);
    });

    // 3. Reset State
    this.selectedHouse = null;
    this.history = [];
    this.notifyHistoryChange();
    this.isSolved = false;
  }

  private handleHouseClick(house: House) {
    if (this.isSolved) return;

    if (!this.selectedHouse) {
      // Select
      this.selectedHouse = house;
      house.setSelection(true);
    } else if (this.selectedHouse === house) {
      // Deselect
      this.selectedHouse.setSelection(false);
      this.selectedHouse = null;
    } else {
      // Attempt Connection
      if (this.cableManager.canConnect(this.selectedHouse, house, this.houses)) {
        // Record History before change
        const prevCount = this.cableManager.hasConnection(this.selectedHouse.dataModel.id, house.dataModel.id);
        this.history.push({
          nodeAId: this.selectedHouse.dataModel.id,
          nodeBId: house.dataModel.id,
          previousCount: prevCount
        });
        this.notifyHistoryChange();

        this.cableManager.toggleConnection(this.selectedHouse, house);
        this.checkWinCondition();
      }

      // Always Deselect after action
      this.selectedHouse.setSelection(false);
      this.selectedHouse = null;
    }
  }

  private undo() {
    if (this.history.length === 0 || this.isSolved) return;

    const lastMove = this.history.pop();
    this.notifyHistoryChange();

    if (lastMove) {
      const houseA = this.houses.find(h => h.dataModel.id === lastMove.nodeAId);
      const houseB = this.houses.find(h => h.dataModel.id === lastMove.nodeBId);

      if (houseA && houseB) {
        this.cableManager.setConnection(houseA, houseB, lastMove.previousCount);
        this.checkWinCondition();
      }
    }
  }

  private notifyHistoryChange() {
    if (this.onEvent) {
      this.onEvent({ type: 'HISTORY_UPDATE', payload: { canUndo: this.history.length > 0 } });
    }
  }

  private checkWinCondition() {
    // 1. Update Connection Counts for all nodes
    const edges = this.cableManager.getAllEdges();

    // Reset counts
    this.houses.forEach(h => h.updateConnectionCount(0));

    // Sum up
    edges.forEach(e => {
      const hA = this.houses.find(h => h.dataModel.id === e.nodeA);
      const hB = this.houses.find(h => h.dataModel.id === e.nodeB);
      if (hA) hA.updateConnectionCount(hA.dataModel.currentConnections + e.count);
      if (hB) hB.updateConnectionCount(hB.dataModel.currentConnections + e.count);
    });

    // 2. Validate Counts
    const allCountsCorrect = this.houses.every(h => h.dataModel.currentConnections === h.dataModel.requiredConnections);

    if (!allCountsCorrect) return;

    // 3. Validate Connectivity (BFS)
    if (this.houses.length === 0) return;

    const startId = this.houses[0].dataModel.id;
    const visited = new Set<string>();
    const queue = [startId];
    visited.add(startId);

    // Build Adjacency List for BFS
    const adj = new Map<string, string[]>();
    edges.forEach(e => {
      if (!adj.has(e.nodeA)) adj.set(e.nodeA, []);
      if (!adj.has(e.nodeB)) adj.set(e.nodeB, []);
      adj.get(e.nodeA)?.push(e.nodeB);
      adj.get(e.nodeB)?.push(e.nodeA);
    });

    while (queue.length > 0) {
      const curr = queue.shift()!;
      const neighbors = adj.get(curr) || [];
      for (const n of neighbors) {
        if (!visited.has(n)) {
          visited.add(n);
          queue.push(n);
        }
      }
    }

    const allConnected = visited.size === this.houses.length;

    if (allConnected) {
      this.victory();
    }
  }

  private victory() {
    this.isSolved = true;
    this.houses.forEach(h => h.setPowered(true));
    this.cableManager.setSolvedState(true);

    // Play sound effect
    this.playVictorySound();

    if (this.onEvent) {
      this.onEvent({ type: 'PUZZLE_SOLVED' });
    }
  }

  private playVictorySound() {
    // Simple Web Audio API synthesis for "Power Up" whirring sound
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;

      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      // Sawtooth wave for a buzzy "electric" feel
      osc.type = 'sawtooth';

      // Pitch ramp up (Powering up)
      osc.frequency.setValueAtTime(110, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(440, ctx.currentTime + 0.4);

      // Volume envelope
      gain.gain.setValueAtTime(0.05, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.1, ctx.currentTime + 0.3);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.2);

      osc.connect(gain);
      gain.connect(ctx.destination);

      osc.start();
      osc.stop(ctx.currentTime + 1.2);

      // Add a second layer (Higher pitch spark)
      const spark = ctx.createOscillator();
      const sparkGain = ctx.createGain();
      spark.type = 'square';
      spark.frequency.setValueAtTime(880, ctx.currentTime);
      spark.frequency.linearRampToValueAtTime(1200, ctx.currentTime + 0.1);

      sparkGain.gain.setValueAtTime(0.03, ctx.currentTime);
      sparkGain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);

      spark.connect(sparkGain);
      sparkGain.connect(ctx.destination);
      spark.start();
      spark.stop(ctx.currentTime + 0.3);

    } catch (e) {
      console.warn("Audio Context not supported or failed", e);
    }
  }
}

import Phaser from 'phaser';
import { EdgeData, NodeData } from '../../types';
import { House } from '../objects/House';

export class CableManager {
  private scene: Phaser.Scene;
  private graphics: Phaser.GameObjects.Graphics;
  private edges: Map<string, EdgeData>; // Key: "idA-idB" (sorted)

  constructor(scene: Phaser.Scene) {
    this.scene = scene;
    this.graphics = scene.add.graphics();
    this.edges = new Map();
  }

  public reset() {
    this.edges.clear();
    this.graphics.clear();
  }

  public getEdgeKey(idA: string, idB: string): string {
    return idA < idB ? `${idA}-${idB}` : `${idB}-${idA}`;
  }

  public hasConnection(idA: string, idB: string): number {
    const key = this.getEdgeKey(idA, idB);
    return this.edges.get(key)?.count || 0;
  }

  public toggleConnection(nodeA: House, nodeB: House): number {
    const key = this.getEdgeKey(nodeA.dataModel.id, nodeB.dataModel.id);
    const current = this.edges.get(key);

    let newCount = 0;
    if (!current) {
      newCount = 1;
    } else if (current.count === 1) {
      newCount = 2;
    } else {
      newCount = 0;
    }

    if (newCount === 0) {
      this.edges.delete(key);
    } else {
      this.edges.set(key, { 
        nodeA: nodeA.dataModel.id, 
        nodeB: nodeB.dataModel.id, 
        count: newCount 
      });
    }

    this.draw();
    return newCount;
  }

  public setConnection(nodeA: House, nodeB: House, count: number) {
    const key = this.getEdgeKey(nodeA.dataModel.id, nodeB.dataModel.id);

    if (count === 0) {
      this.edges.delete(key);
    } else {
      this.edges.set(key, { 
        nodeA: nodeA.dataModel.id, 
        nodeB: nodeB.dataModel.id, 
        count: count 
      });
    }

    this.draw();
  }

  public canConnect(nodeA: House, nodeB: House, allNodes: House[]): boolean {
    const dA = nodeA.dataModel;
    const dB = nodeB.dataModel;

    // 1. Orthogonal check
    if (dA.x !== dB.x && dA.y !== dB.y) return false;

    // 2. Node between check
    const isVertical = dA.x === dB.x;
    for (const other of allNodes) {
      if (other === nodeA || other === nodeB) continue;
      const dO = other.dataModel;

      if (isVertical) {
        if (dO.x === dA.x && 
           ((dO.y > dA.y && dO.y < dB.y) || (dO.y > dB.y && dO.y < dA.y))) return false;
      } else {
        if (dO.y === dA.y && 
           ((dO.x > dA.x && dO.x < dB.x) || (dO.x > dB.x && dO.x < dA.x))) return false;
      }
    }

    // 3. Cable crossing check
    // Logic: If we are drawing vertical, check against all horizontal edges in range
    const newMinX = Math.min(dA.x, dB.x);
    const newMaxX = Math.max(dA.x, dB.x);
    const newMinY = Math.min(dA.y, dB.y);
    const newMaxY = Math.max(dA.y, dB.y);

    for (const edge of this.edges.values()) {
      const n1 = allNodes.find(n => n.dataModel.id === edge.nodeA)!;
      const n2 = allNodes.find(n => n.dataModel.id === edge.nodeB)!;

      // Skip if connected to same nodes (updating existing edge is fine)
      if (edge.nodeA === dA.id || edge.nodeA === dB.id || 
          edge.nodeB === dA.id || edge.nodeB === dB.id) continue;

      const eIsVert = n1.dataModel.x === n2.dataModel.x;

      if (isVertical && !eIsVert) {
        // New is Vert, Existing is Horiz -> Possible cross
        const eY = n1.dataModel.y;
        const eMinX = Math.min(n1.dataModel.x, n2.dataModel.x);
        const eMaxX = Math.max(n1.dataModel.x, n2.dataModel.x);

        if (dA.x > eMinX && dA.x < eMaxX && eY > newMinY && eY < newMaxY) return false;
      } else if (!isVertical && eIsVert) {
        // New is Horiz, Existing is Vert -> Possible cross
        const eX = n1.dataModel.x;
        const eMinY = Math.min(n1.dataModel.y, n2.dataModel.y);
        const eMaxY = Math.max(n1.dataModel.y, n2.dataModel.y);

        if (dA.y > eMinY && dA.y < eMaxY && eX > newMinX && eX < newMaxX) return false;
      }
    }

    return true;
  }

  public getAllEdges() {
    return Array.from(this.edges.values());
  }

  public setSolvedState(isSolved: boolean) {
    this.draw(isSolved);
  }

  private draw(isSolved: boolean = false) {
    this.graphics.clear();
    const color = isSolved ? 0xffcc00 : 0x666666;

    this.edges.forEach(edge => {
      const nodeA = this.scene.children.getByName(edge.nodeA) as House;
      const nodeB = this.scene.children.getByName(edge.nodeB) as House;

      if (nodeA && nodeB) {
        if (edge.count === 1) {
          // Changed from 3 to 4
          this.graphics.lineStyle(4, color, 1);
          this.graphics.beginPath();
          this.graphics.moveTo(nodeA.x, nodeA.y);
          this.graphics.lineTo(nodeB.x, nodeB.y);
          this.graphics.strokePath();
        } else {
          // Double line
          const isVert = nodeA.x === nodeB.x;
          const offset = 5;

          // Changed from 2 to 3
          this.graphics.lineStyle(3, color, 1);

          if (isVert) {
            this.graphics.beginPath();
            this.graphics.moveTo(nodeA.x - offset, nodeA.y);
            this.graphics.lineTo(nodeB.x - offset, nodeB.y);
            this.graphics.moveTo(nodeA.x + offset, nodeA.y);
            this.graphics.lineTo(nodeB.x + offset, nodeB.y);
            this.graphics.strokePath();
          } else {
            this.graphics.beginPath();
            this.graphics.moveTo(nodeA.x, nodeA.y - offset);
            this.graphics.lineTo(nodeB.x, nodeB.y - offset);
            this.graphics.moveTo(nodeA.x, nodeA.y + offset);
            this.graphics.lineTo(nodeB.x, nodeB.y + offset);
            this.graphics.strokePath();
          }
        }
      }
    });
  }
}

export enum Difficulty {
  EASY = 'easy',
  MEDIUM = 'medium',
  HARD = 'hard',
}

export enum Theme {
  POWER_GRID = 'POWER_GRID',
  PENGUINS = 'PENGUINS',
}

export interface DifficultyConfig {
  gridSize: number;
  nodeCount: [number, number]; // min, max
  maxConnections: number;
  scale: number;
}

export const DIFFICULTY_SETTINGS: Record<Difficulty, DifficultyConfig> = {
  [Difficulty.EASY]: {
    gridSize: 5,
    nodeCount: [6, 9],
    maxConnections: 4,
    scale: 1.0,
  },
  [Difficulty.MEDIUM]: {
    gridSize: 7,
    nodeCount: [8, 12],
    maxConnections: 6,
    scale: 0.85,
  },
  [Difficulty.HARD]: {
    gridSize: 10,
    nodeCount: [12, 18],
    maxConnections: 8,
    scale: 0.7,
  },
};

export interface GridPoint {
  x: number;
  y: number;
}

// Logic representation of a House
export interface NodeData {
  id: string;
  x: number;
  y: number;
  requiredConnections: number;
  currentConnections: number;
}

// Logic representation of a Cable
export interface EdgeData {
  nodeA: string;
  nodeB: string;
  count: number; // 1 or 2
}

export interface GameStats {
  easy: { completed: number; time: number };
  medium: { completed: number; time: number };
  hard: { completed: number; time: number };
}

// Events emitted from Phaser to React
export type GameEventType = 'PUZZLE_SOLVED' | 'TIMER_TICK' | 'PUZZLE_IMPOSSIBLE' | 'HISTORY_UPDATE';

export interface GameEvent {
  type: GameEventType;
  payload?: any;
}

import React, { useEffect, useRef, useState } from 'react';
import { createGame, gameInstance } from './game/phaserGame';
import { GameScene } from './game/scenes/GameScene';
import { Difficulty, GameEvent, Theme } from './types';
import { RotateCcw, Flag, Play, HelpCircle, Trophy, Undo, SkipForward, AlertTriangle, Clock, Gauge, X, Check, Zap, Snowflake } from 'lucide-react';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<'START' | 'INSTRUCTIONS' | 'PLAYING' | 'VICTORY' | 'FINISHED'>('START');
  const [difficulty, setDifficulty] = useState<Difficulty>(Difficulty.EASY);
  const [theme, setTheme] = useState<Theme>(Theme.POWER_GRID);

  // Session Settings
  const [sessionMinutes, setSessionMinutes] = useState<number>(5);
  const [timeLeft, setTimeLeft] = useState(0);

  // UI State
  const [showRules, setShowRules] = useState(true);
  const [showReportPopup, setShowReportPopup] = useState(false);
  const [showDiffSelector, setShowDiffSelector] = useState(false);
  const [canUndo, setCanUndo] = useState(false);

  // Session Stats
  const [stats, setStats] = useState({
    [Difficulty.EASY]: 0,
    [Difficulty.MEDIUM]: 0,
    [Difficulty.HARD]: 0,
  });

  const timerIntervalRef = useRef<number | null>(null);

  // Ref to hold latest state for the Phaser event callback (avoids stale closures)
  const stateRef = useRef({ difficulty, timeLeft, gameState });

  // Sync state to ref
  useEffect(() => {
    stateRef.current = { difficulty, timeLeft, gameState };
  }, [difficulty, timeLeft, gameState]);

  // Initialize Game
  useEffect(() => {
    const game = createGame('game-container');

    // Bridge Events
    game.events.on('ready', () => {
       const runningScene = game.scene.keys['GameScene'] as GameScene;
       runningScene.onEvent = handleGameEvent;
    });

    return () => {
      game.destroy(true);
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    };
  }, []);

  // Timer Logic: Pause if any modal is open or game is not playing
  useEffect(() => {
    // Timer only runs when explicitly PLAYING and no popups are open
    const isPaused = showRules || showReportPopup || showDiffSelector || gameState !== 'PLAYING';

    if (!isPaused && timeLeft > 0) {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);

      timerIntervalRef.current = window.setInterval(() => {
        setTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    } else {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }

    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    };
  }, [gameState, showRules, showReportPopup, showDiffSelector]); 

  // Check for Session End
  useEffect(() => {
    if (timeLeft === 0 && gameState === 'PLAYING') {
      setGameState('FINISHED');
    }
  }, [timeLeft, gameState]);

  const handleGameEvent = (event: GameEvent) => {
    if (event.type === 'PUZZLE_SOLVED') {
      const { difficulty: currentDifficulty } = stateRef.current;

      setGameState('VICTORY');
      setStats(prev => ({
        ...prev,
        [currentDifficulty]: prev[currentDifficulty] + 1
      }));
    } else if (event.type === 'HISTORY_UPDATE') {
      setCanUndo(event.payload.canUndo);
    }
  };

  const handleStartSession = () => {
    setStats({ [Difficulty.EASY]: 0, [Difficulty.MEDIUM]: 0, [Difficulty.HARD]: 0 });
    setTimeLeft(sessionMinutes * 60);
    // Transition to instructions first, do not start game or timer yet
    setGameState('INSTRUCTIONS');
    setShowRules(false);
  };

  const handleBeginPlay = () => {
    setGameState('PLAYING');
    // Start the first puzzle only after instructions are acknowledged
    launchPuzzle(difficulty, theme);
  }

  const launchPuzzle = (diff: Difficulty, thm: Theme) => {
    const scene = gameInstance?.scene.getScene('GameScene') as GameScene;
    if (scene) {
      scene.events.emit('START_GAME', { difficulty: diff, theme: thm });
    }
  };

  const handleNextPuzzle = () => {
    setGameState('PLAYING');
    launchPuzzle(difficulty, theme);
  };

  const handleRestart = () => {
    if (gameState !== 'PLAYING') return;
    const scene = gameInstance?.scene.getScene('GameScene') as GameScene;
    if (scene) {
      scene.events.emit('RESET_PUZZLE');
    }
  };

  const handleSkip = () => {
    if (gameState !== 'PLAYING') return;
    launchPuzzle(difficulty, theme);
  };

  const handleUndo = () => {
    if (gameState !== 'PLAYING') return;
    const scene = gameInstance?.scene.getScene('GameScene') as GameScene;
    if (scene) {
      scene.events.emit('UNDO');
    }
  };

  const handleChangeDifficulty = (newDiff: Difficulty) => {
    setDifficulty(newDiff);
    setShowDiffSelector(false);
    launchPuzzle(newDiff, theme);
  };

  const handleReportClick = () => {
    if (gameState === 'PLAYING') {
      setShowReportPopup(true);
    }
  };

  const confirmReport = () => {
    const scene = gameInstance?.scene.getScene('GameScene') as GameScene;
    if (scene) {
      scene.events.emit('REPORT_UNSOLVABLE');
    }
    handleSkip();
    setShowReportPopup(false);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  // --- THEME & STYLING ---

  const isPenguin = theme === Theme.PENGUINS;

  const bgClass = isPenguin ? "bg-sky-950" : "bg-slate-900";
  const containerBorderClass = isPenguin ? "border-sky-700 bg-sky-900" : "border-slate-700 bg-slate-800";
  const hudBgClass = isPenguin ? "bg-sky-900/90 border-sky-600" : "bg-slate-800/90 border-slate-700";
  const accentTextClass = isPenguin ? "text-cyan-400" : "text-yellow-400";
  const accentBorderClass = isPenguin ? "border-cyan-400" : "border-yellow-400";
  const primaryButtonClass = isPenguin ? "bg-cyan-600 hover:bg-cyan-500 border-cyan-800" : "bg-green-600 hover:bg-green-500 border-green-800";

  const getDiffButtonClass = (d: Difficulty) => {
    const isSelected = difficulty === d;
    const base = "py-2 rounded capitalize font-bold transition border-2";

    // Unselected state
    if (!isSelected) {
      return isPenguin 
        ? `${base} bg-sky-800 border-transparent text-sky-400 hover:bg-sky-700`
        : `${base} bg-slate-700 border-transparent text-slate-400 hover:bg-slate-600`;
    }

    // Selected state
    switch (d) {
        case Difficulty.EASY: return `${base} bg-green-600 border-green-400 text-white`;
        case Difficulty.MEDIUM: return `${base} bg-yellow-600 border-yellow-400 text-white`;
        case Difficulty.HARD: return `${base} bg-red-600 border-red-400 text-white`;
        default: return base;
    }
  };

  const getThemeButtonClass = (t: Theme) => {
    const isSelected = theme === t;
    const base = "py-4 rounded font-bold transition border-2 flex flex-col items-center justify-center gap-2";
    if (isSelected) {
      return t === Theme.PENGUINS 
        ? `${base} bg-sky-600 border-cyan-400 text-white shadow-[0_0_15px_rgba(34,211,238,0.5)]`
        : `${base} bg-slate-700 border-yellow-400 text-white shadow-[0_0_15px_rgba(250,204,21,0.5)]`;
    }
    return `${base} bg-slate-800 border-slate-600 text-slate-400 hover:bg-slate-700 opacity-60 hover:opacity-100`;
  }

  const totalSolved = stats[Difficulty.EASY] + stats[Difficulty.MEDIUM] + stats[Difficulty.HARD];

  return (
    <div className={`relative w-full h-screen ${bgClass} flex justify-center items-center overflow-hidden p-2 transition-colors duration-500`}>
      {/* Game Container - Scalable 4:3 Box */}
      <div 
        id="game-container" 
        className={`relative w-full h-full max-w-[100vw] max-h-full aspect-[4/3] rounded-lg shadow-2xl border-4 transition-colors duration-500 ${containerBorderClass}`}
      >
        {/* HUD Overlay - Positioned Inside Container */}
        <div className="absolute inset-0 p-4 pointer-events-none z-10 flex flex-col justify-between">

          {/* TOP BAR */}
          <div className="flex justify-between items-start w-full">
            {/* Top Left: Stats */}
            <div className={`${hudBgClass} text-white p-3 rounded shadow-lg pointer-events-auto backdrop-blur-sm border min-w-[140px] transition-colors`}>
              <h3 className={`font-bold ${accentTextClass} mb-2 flex items-center gap-2 border-b border-white/20 pb-1`}>
                <Trophy size={16} /> Solved: {totalSolved}
              </h3>
              <div className="text-sm font-mono space-y-1">
                <div className="flex justify-between text-green-400"><span>Easy:</span> <span>{stats[Difficulty.EASY]}</span></div>
                <div className="flex justify-between text-yellow-400"><span>Medium:</span> <span>{stats[Difficulty.MEDIUM]}</span></div>
                <div className="flex justify-between text-red-400"><span>Hard:</span> <span>{stats[Difficulty.HARD]}</span></div>
              </div>
            </div>

            {/* Top Center: Timer */}
            <div className={`${hudBgClass} text-white px-6 py-2 rounded-full shadow-lg font-mono text-xl font-bold border-2 backdrop-blur-sm transition-colors ${timeLeft < 30 ? 'border-red-500 text-red-400 animate-pulse' : 'border-transparent'}`}>
              {formatTime(timeLeft)}
            </div>

            {/* Top Right: Controls */}
            <div className={`${hudBgClass} p-2 rounded shadow-lg pointer-events-auto flex gap-2 backdrop-blur-sm items-start border transition-colors`}>
              <button 
                onClick={() => setShowRules(true)}
                className="bg-blue-600 text-white rounded hover:bg-blue-500 transition w-[44px] flex items-center justify-center h-[96px]" 
                title="Rules"
              >
                <HelpCircle size={24} />
              </button>

              <div className="flex flex-col gap-2">
                <div className="flex gap-2">
                    <button 
                      onClick={handleUndo}
                      disabled={!canUndo || gameState !== 'PLAYING'}
                      className="bg-slate-600 text-white rounded hover:bg-slate-500 transition disabled:opacity-50 disabled:cursor-not-allowed h-[44px] w-[44px] flex items-center justify-center" 
                      title="Undo">
                      <Undo size={20} />
                    </button>
                    <button 
                      onClick={() => setShowDiffSelector(true)}
                      disabled={gameState !== 'PLAYING'}
                      className="bg-purple-600 text-white rounded hover:bg-purple-500 transition disabled:opacity-50 disabled:cursor-not-allowed h-[44px] w-[44px] flex items-center justify-center" 
                      title="Change Difficulty">
                      <Gauge size={20} />
                    </button>
                </div>
                <div className="flex gap-2">
                    <button 
                        onClick={handleRestart}
                        disabled={gameState !== 'PLAYING'}
                        className="bg-orange-600 text-white rounded hover:bg-orange-500 transition disabled:opacity-50 disabled:cursor-not-allowed h-[44px] w-[44px] flex items-center justify-center" 
                        title="Reset Connections">
                        <RotateCcw size={20} />
                      </button>
                    <button 
                      onClick={handleSkip}
                      disabled={gameState !== 'PLAYING'}
