    this.events.on('START_GAME', (data: { difficulty: Difficulty, theme: Theme }) => {
      this.startGame(data.difficulty, data.theme);
    });

    this.events.on('RESET_PUZZLE', () => {
      this.resetCurrentPuzzle();
